def get_ports(MAP_DATA): # to print all ports and manually rename the keys into real life port names
    count = 0;
    dic = dict({})
    for r, row in enumerate(MAP_DATA):
        for c, col in enumerate(row):
            if MAP_DATA[r][c] == 5:
                dic[count] = (r, c)
                count += 1

    print(f"PORT_NAMES = {dic}")